INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('ADVANCED_GROWTH: Le PLG flywheel: free users → power users → teams → enterprise. Chaque etape alimente la suivante.', 'PLG flywheel: free → power → teams → enterprise', 'ceo', 'best_practice', 0.85, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le bottoms-up adoption (un employe adopte, puis l equipe, puis l entreprise) est la croissance PLG ideale.', 'Bottoms-up adoption: employe → equipe → entreprise', 'ceo', 'insight', 0.82, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le time-to-wow (temps avant que le client dise wow) doit etre < 30 secondes pour les apps consumer.', 'Time-to-wow < 30s apps consumer', 'onboarding', 'best_practice', 0.82, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le activation metric (la mesure specifique du aha moment) varie par produit. Pour KeiroAI: premier agent qui produit un resultat.', 'Activation metric KeiroAI: premier agent → resultat', 'onboarding', 'best_practice', 0.90, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le habit loop (cue → routine → reward) doit etre design dans le produit pour creer l usage quotidien.', 'Habit loop: cue → routine → reward = usage quotidien', 'retention', 'best_practice', 0.82, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le network effect direct: plus d utilisateurs = plus de valeur pour chaque utilisateur (ex: marketplace).', 'Network effect direct: plus users = plus valeur/user', 'ceo', 'insight', 0.85, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le data network effect: plus d utilisateurs = plus de donnees = meilleur produit = plus d utilisateurs.', 'Data network effect: users → data → meilleur produit → users', 'ceo', 'insight', 0.85, 'massive_boost_51', 'system'),
('PRICING_MODEL: Le seat-based pricing (par utilisateur) est le plus previsible pour le client et le plus simple a comprendre.', 'Seat-based pricing = previsible + simple', 'ceo', 'insight', 0.82, 'massive_boost_52', 'system'),
('PRICING_MODEL: Le usage-based pricing (pay-as-you-go) aligne le prix avec la valeur percue. Ideal pour les APIs et infrastructures.', 'Usage-based = aligner prix/valeur. Ideal APIs/infra', 'ceo', 'insight', 0.82, 'massive_boost_52', 'system'),
('PRICING_MODEL: Le tiered pricing (plans par niveau) est le plus courant pour les SaaS. 3-4 tiers est optimal.', 'Tiered pricing SaaS: 3-4 plans optimal', 'ceo', 'best_practice', 0.85, 'massive_boost_52', 'system'),
('PRICING_MODEL: Le flat-rate pricing (prix unique) est le plus simple mais ne capture pas la valeur des gros clients.', 'Flat-rate: simple mais ne capture pas valeur gros clients', 'ceo', 'insight', 0.80, 'massive_boost_52', 'system'),
('PRICING_MODEL: Le hybrid pricing (base fixe + usage variable) combine previsibilite et alignement avec la valeur.', 'Hybrid pricing: base fixe + usage variable = previsible + aligne', 'ceo', 'insight', 0.82, 'massive_boost_52', 'system'),
('CUSTOMER_INTERVIEW: Les 5 questions essentielles: quel probleme?, comment le resolvez-vous?, qu est-ce qui ne fonctionne pas?, budget?, timeline?', 'Interview client: probleme? resolution? blocage? budget? timeline?', 'commercial', 'best_practice', 0.85, 'massive_boost_53', 'system'),
('CUSTOMER_INTERVIEW: Le Mom Test (Rob Fitzpatrick): poser des questions sur le comportement passe, pas sur les opinions futures.', 'Mom Test: questions comportement passe, pas opinions futures', 'ceo', 'best_practice', 0.88, 'massive_boost_53', 'system'),
('CUSTOMER_INTERVIEW: Ne jamais demander si le client acheterait votre produit. Observer ce qu il fait, pas ce qu il dit.', 'Ne pas demander si acheterait. Observer les actions', 'ceo', 'best_practice', 0.88, 'massive_boost_53', 'system'),
('CUSTOMER_INTERVIEW: 10 interviews suffisent pour trouver des patterns. Si les 10 disent la meme chose, c est un signal fort.', '10 interviews = patterns. Meme reponse 10x = signal fort', 'ceo', 'insight', 0.85, 'massive_boost_53', 'system'),
('CUSTOMER_INTERVIEW: Les questions follow-up (pourquoi? pouvez-vous me donner un exemple?) revelent les insights profonds.', 'Questions follow-up pourquoi/exemple = insights profonds', 'ceo', 'best_practice', 0.85, 'massive_boost_53', 'system'),
('SEO_ADVANCED: Le topical map (cartographie de tous les sujets a couvrir) structure la strategie de contenu SEO sur 12 mois.', 'Topical map = strategie contenu SEO 12 mois', 'seo', 'best_practice', 0.85, 'massive_boost_54', 'system'),
('SEO_ADVANCED: Le link building par la creation de contenu remarquable (etudes, outils gratuits, infographies) est la methode la plus durable.', 'Link building par contenu remarquable = plus durable', 'seo', 'best_practice', 0.85, 'massive_boost_54', 'system'),
('SEO_ADVANCED: Le internal link audit trimestriel (verifier les liens casses, optimiser les ancres) ameliore le crawl de 20%.', 'Internal link audit trimestriel = +20% crawl', 'seo', 'best_practice', 0.82, 'massive_boost_54', 'system'),
('SEO_ADVANCED: Le keyword cannibalization check (2 pages qui ciblent le meme mot-cle) doit etre fait mensuellement.', 'Keyword cannibalization check mensuel', 'seo', 'best_practice', 0.82, 'massive_boost_54', 'system'),
('SEO_ADVANCED: Le log file analysis (analyser les logs du serveur) revele comment Google crawle le site. Essentiel pour les grands sites.', 'Log file analysis = comprendre crawl Google', 'seo', 'best_practice', 0.78, 'massive_boost_54', 'system'),
('ADS_ADVANCED: Le creative fatigue se detecte par: CTR en baisse, CPM en hausse, frequency > 5. Renouveler les visuels.', 'Creative fatigue: CTR baisse, CPM hausse, frequency >5 = renouveler', 'ads', 'insight', 0.85, 'massive_boost_55', 'system'),
('ADS_ADVANCED: Le look-alike audience a 1% est la plus precise. 2-5% pour le scaling. >5% perd en precision.', 'Lookalike: 1% precis, 2-5% scaling, >5% imprecis', 'ads', 'best_practice', 0.85, 'massive_boost_55', 'system'),
('ADS_ADVANCED: Le conversion API (server-side tracking) remplace progressivement le pixel client-side suite aux restrictions iOS.', 'Conversion API server-side remplace pixel client (iOS)', 'ads', 'insight', 0.82, 'massive_boost_55', 'system'),
('ADS_ADVANCED: Le UTM tagging systematique (utm_source, utm_medium, utm_campaign, utm_content) est la base de l attribution.', 'UTM systematique = base attribution marketing', 'ads', 'best_practice', 0.88, 'massive_boost_55', 'system'),
('ADS_ADVANCED: Le ad creative testing: tester le hook (2s premieres), le body (message), et le CTA separement.', 'Creative testing: hook + body + CTA separement', 'ads', 'best_practice', 0.82, 'massive_boost_55', 'system'),
('STARTUP_OPS: La documentation des processes dans Notion est le fondement de l execution scalable.', 'Documentation Notion = fondement execution scalable', 'ceo', 'best_practice', 0.82, 'massive_boost_56', 'system'),
('STARTUP_OPS: Le weekly all-hands (15 min max) aligne toute l equipe: wins, focus, blockers.', 'Weekly all-hands 15 min: wins, focus, blockers', 'ceo', 'best_practice', 0.80, 'massive_boost_56', 'system'),
('STARTUP_OPS: Le async-first culture (communication ecrite > reunions) est 30% plus productif pour les equipes distribuees.', 'Async-first: ecrit > reunions = +30% productivite distribuee', 'rh', 'insight', 0.82, 'massive_boost_56', 'system'),
('STARTUP_OPS: Le KPI tree (metriques en arbre: north star → sub-metrics → actionable metrics) aligne toutes les equipes.', 'KPI tree: north star → sub-metrics → actionable. Aligner equipes', 'ceo', 'best_practice', 0.82, 'massive_boost_56', 'system'),
('STARTUP_OPS: Le decision log (documenter chaque decision importante: contexte, options, decision, raisons) evite de refaire les debats.', 'Decision log: contexte + options + decision + raisons = pas refaire debats', 'ceo', 'best_practice', 0.80, 'massive_boost_56', 'system'),
('EMAIL_ADV: Les triggered emails generent 75% des revenus email avec seulement 20% des envois. Prioriser les automations.', 'Triggered emails: 75% revenus avec 20% envois. Prioriser', 'email', 'insight', 0.85, 'massive_boost_57', 'system'),
('EMAIL_ADV: Le email frequency sweet spot: 2-3/semaine pour le nurturing, 1/semaine pour la newsletter, 3-5/jour MAX pour le transactionnel.', 'Frequence email: 2-3/sem nurturing, 1/sem newsletter, 3-5/j transactionnel', 'email', 'best_practice', 0.82, 'massive_boost_57', 'system'),
('EMAIL_ADV: Le dynamic content blocks (contenu different par segment dans le meme email) augmente le CTR de 30%.', 'Dynamic content blocks = +30% CTR', 'email', 'insight', 0.82, 'massive_boost_57', 'system'),
('EMAIL_ADV: Le email testing checklist: sujet, preheader, from name, mobile rendering, liens, CTA, tracking, unsubscribe.', 'Testing checklist: sujet, preheader, from, mobile, liens, CTA, tracking, unsub', 'email', 'best_practice', 0.85, 'massive_boost_57', 'system'),
('EMAIL_ADV: Le bounce management: hard bounces = supprimer immediatement. Soft bounces = retry 3 fois puis supprimer.', 'Bounce: hard = supprimer. Soft = retry 3x puis supprimer', 'email', 'best_practice', 0.88, 'massive_boost_57', 'system'),
('SOCIAL_ADV: Le social media ROI se mesure par: leads generes, trafic vers le site, mentions de marque, engagement rate.', 'Social ROI: leads + trafic + mentions + engagement', 'content', 'best_practice', 0.82, 'massive_boost_58', 'system'),
('SOCIAL_ADV: Le content calendar doit inclure: date, plateforme, format, sujet, visuel, copy, CTA, statut.', 'Content calendar: date + plateforme + format + sujet + visuel + copy + CTA + statut', 'content', 'best_practice', 0.85, 'massive_boost_58', 'system'),
('SOCIAL_ADV: Le community guidelines (regles de la communaute) doivent etre definies et publiees pour moderer efficacement.', 'Community guidelines = regles publiees pour moderation', 'marketing', 'best_practice', 0.80, 'massive_boost_58', 'system'),
('SOCIAL_ADV: Le social media crisis plan: detecter en < 1h, evaluer, repondre, escalader si necessaire, documenter.', 'Social crisis plan: detecter <1h, evaluer, repondre, escalader, documenter', 'marketing', 'best_practice', 0.82, 'massive_boost_58', 'system'),
('SOCIAL_ADV: Le brand monitoring (surveiller les mentions: nom, produit, fondateur, hashtags) est obligatoire quotidiennement.', 'Brand monitoring quotidien: nom + produit + fondateur + hashtags', 'marketing', 'best_practice', 0.82, 'massive_boost_58', 'system'),
('CHATBOT_ADV: Le conversational UX design: messages courts (< 2 phrases), boutons de reponse, transitions fluides.', 'Conversational UX: courts messages + boutons + transitions fluides', 'chatbot', 'best_practice', 0.85, 'massive_boost_59', 'system'),
('CHATBOT_ADV: Le intent detection accuracy doit etre > 85% pour eviter la frustration. En dessous, retrainer le modele.', 'Intent detection > 85%. Sinon retrainer', 'chatbot', 'best_practice', 0.82, 'massive_boost_59', 'system'),
('CHATBOT_ADV: Le fallback message (quand le bot ne comprend pas) doit proposer 3 options: reformuler, changer de sujet, parler a un humain.', 'Fallback chatbot: reformuler + changer sujet + humain', 'chatbot', 'best_practice', 0.82, 'massive_boost_59', 'system'),
('CHATBOT_ADV: Le chatbot analytics: messages/jour, resolution rate, CSAT, escalation rate, top intents. Analyser hebdomadairement.', 'Chatbot analytics hebdo: messages, resolution, CSAT, escalation, intents', 'chatbot', 'best_practice', 0.82, 'massive_boost_59', 'system'),
('CHATBOT_ADV: Le handoff chatbot→humain doit transmettre tout le contexte de la conversation pour eviter que le client repete.', 'Handoff chatbot→humain: transmettre contexte complet', 'chatbot', 'best_practice', 0.88, 'massive_boost_59', 'system'),
('KEIROAI_FINAL: KeiroAI transforme chaque entrepreneur en directeur marketing avec une equipe IA d elite a ses cotes.', 'KeiroAI = chaque entrepreneur devient directeur marketing', 'ceo', 'best_practice', 0.95, 'massive_boost_60', 'system'),
('KEIROAI_FINAL: Le futur de KeiroAI: agents de plus en plus autonomes, intelligence toujours plus fine, resultats toujours meilleurs.', 'KeiroAI futur: autonomie + intelligence + resultats', 'ceo', 'insight', 0.90, 'massive_boost_60', 'system'),
('KEIROAI_FINAL: La promesse de KeiroAI: le client dort, ses agents travaillent. Le marketing ne s arrete jamais.', 'KeiroAI promesse: client dort, agents travaillent 24/7', 'ceo', 'best_practice', 0.92, 'massive_boost_60', 'system')
ON CONFLICT DO NOTHING;
