INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('SECTOR_SAAS_1: Le CAC moyen pour un SaaS B2B en France: 200-500€. B2C: 30-100€. Le CAC doit etre < LTV/3.', 'CAC SaaS FR: B2B 200-500€, B2C 30-100€. CAC < LTV/3', 'ceo', 'insight', 0.82, 'massive_boost_44b', 'system'),
('SECTOR_SAAS_2: Le ACV (Annual Contract Value) moyen pour les SaaS SMB: 1000-5000€. Mid-market: 10K-50K€. Enterprise: 50K-500K€.', 'ACV SaaS: SMB 1-5K, mid 10-50K, enterprise 50-500K', 'ceo', 'insight', 0.80, 'massive_boost_44b', 'system'),
('SECTOR_SAAS_3: Le logo retention (% clients qui restent) doit etre > 85% annuel pour les SaaS sains.', 'Logo retention > 85% annuel = SaaS sain', 'ceo', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('SECTOR_SAAS_4: Le expansion revenue (upsell+cross-sell) doit compenser 30%+ du churn pour un net dollar retention >100%.', 'Expansion compenser 30%+ churn = NDR >100%', 'ceo', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('SECTOR_SAAS_5: Le magic number (net new ARR / S&M spend du trimestre precedent) > 0.75 = efficient growth.', 'Magic number > 0.75 = efficient growth', 'ceo', 'insight', 0.82, 'massive_boost_44b', 'system'),
('LANDING_1: Le split testing des headlines est le test le plus impactant: +20-50% conversion avec le bon titre.', 'Split test headlines = +20-50% conversion', 'commercial', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('LANDING_2: Le social proof placement (juste avant le CTA) augmente les conversions de 12%.', 'Social proof avant CTA = +12% conversion', 'commercial', 'insight', 0.82, 'massive_boost_44b', 'system'),
('LANDING_3: Les micro-copy (texte sous les champs de formulaire, pres des boutons) reduit l anxiete et augmente les completions de 15%.', 'Micro-copy = -anxiete +15% completions', 'commercial', 'insight', 0.80, 'massive_boost_44b', 'system'),
('LANDING_4: Le power of one: une landing page, un message, une audience, un CTA. La simplicite convertit.', 'Power of one: 1 page, 1 message, 1 audience, 1 CTA', 'commercial', 'best_practice', 0.88, 'massive_boost_44b', 'system'),
('LANDING_5: Le directional cues (fleches, regards diriges vers le CTA) guident l oeil et augmentent les clics de 10%.', 'Directional cues vers CTA = +10% clics', 'commercial', 'insight', 0.78, 'massive_boost_44b', 'system'),
('AUTOMATION_1: Le lead routing intelligent (assigner le lead au commercial le plus pertinent par expertise/geo) augmente la conversion de 25%.', 'Lead routing intelligent = +25% conversion', 'commercial', 'insight', 0.82, 'massive_boost_44b', 'system'),
('AUTOMATION_2: Le SLA alert (notification si un lead n est pas contacte dans les 5 min) augmente le taux de connexion de 40%.', 'SLA alert 5 min = +40% taux connexion leads', 'commercial', 'insight', 0.82, 'massive_boost_44b', 'system'),
('AUTOMATION_3: Le data enrichment automatique (Clearbit, Apollo) ajoute firmographic data a chaque lead sans effort.', 'Data enrichment auto = firmographic data sans effort', 'commercial', 'insight', 0.80, 'massive_boost_44b', 'system'),
('AUTOMATION_4: Le automated QA (verification automatique de la qualite des contenus generes) evite les erreurs embarrassantes.', 'Auto QA contenu = eviter erreurs embarrassantes', 'content', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('AUTOMATION_5: Le report generation automatique (dashboards auto-mis-a-jour) economise 5h/semaine d analyse manuelle.', 'Reports auto = -5h/semaine analyse manuelle', 'ceo', 'insight', 0.82, 'massive_boost_44b', 'system'),
('WHATSAPP_1: Le WhatsApp Business API permet l envoi de messages template pre-approuves en masse (notifications, confirmations).', 'WhatsApp Business API: templates pre-approuves en masse', 'whatsapp', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('WHATSAPP_2: Le chatbot WhatsApp (avec boutons interactifs) a un taux de resolution de 60% sans intervention humaine.', 'Chatbot WhatsApp boutons = 60% resolution sans humain', 'whatsapp', 'insight', 0.82, 'massive_boost_44b', 'system'),
('WHATSAPP_3: Les WhatsApp Flows (formulaires interactifs dans WhatsApp) simplifient la collecte d infos et les reservations.', 'WhatsApp Flows = formulaires interactifs in-app', 'whatsapp', 'insight', 0.80, 'massive_boost_44b', 'system'),
('WHATSAPP_4: Le opt-in WhatsApp doit etre explicite (RGPD). Ne jamais ajouter de contacts sans consentement.', 'WhatsApp opt-in explicite RGPD. Jamais sans consentement', 'whatsapp', 'best_practice', 0.90, 'massive_boost_44b', 'system'),
('WHATSAPP_5: Le abandoned cart WhatsApp (relance 1h apres abandon) a un taux de recuperation de 20-35%.', 'Abandoned cart WhatsApp 1h = 20-35% recuperation', 'whatsapp', 'insight', 0.82, 'massive_boost_44b', 'system'),
('DM_1: Le warm intro DM (reagir a une story PUIS envoyer le DM) a un taux de reponse 5x superieur au cold DM.', 'Warm intro via story = 5x reponse vs cold DM', 'dm_instagram', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('DM_2: Le question-based DM (poser une question sincere au lieu de pitcher) ouvre 35% de conversations.', 'DM question sincere = 35% conversations ouvertes', 'dm_instagram', 'insight', 0.82, 'massive_boost_44b', 'system'),
('DM_3: Le value-first DM (offrir quelque chose de gratuit: audit, template, conseil) avant de demander quoi que ce soit.', 'DM value-first: offrir gratuit avant demander', 'dm_instagram', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('DM_4: Le DM automation doit rester naturel. Les messages qui semblent automatises sont ignores a 80%.', 'DM auto doit sembler naturel. Auto apparent = 80% ignore', 'dm_instagram', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('DM_5: Le closing en DM: proposer un appel de 15 min via Calendly au lieu de pitcher par ecrit.', 'DM closing: Calendly 15 min > pitch ecrit', 'dm_instagram', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('GMAPS_1: Les fiches Google My Business doivent etre verifiees. Les fiches non verifiees n apparaissent pas dans le pack local.', 'GMB: verification obligatoire. Non verifie = invisible', 'gmaps', 'best_practice', 0.90, 'massive_boost_44b', 'system'),
('GMAPS_2: Les categories GMB (principale + secondaires) doivent etre choisies strategiquement pour maximiser la visibilite.', 'Categories GMB strategiques = max visibilite', 'gmaps', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('GMAPS_3: Les short URLs Google (g.page/votrebusiness) facilitent le partage et la demande d avis.', 'Short URL g.page = faciliter partage + demande avis', 'gmaps', 'best_practice', 0.80, 'massive_boost_44b', 'system'),
('GMAPS_4: Les offres GMB (section Offres de la fiche) augmentent les clics de 20% et les conversions de 10%.', 'Offres GMB = +20% clics +10% conversions', 'gmaps', 'insight', 0.80, 'massive_boost_44b', 'system'),
('GMAPS_5: Le response time aux messages GMB doit etre < 24h. Google penalise les entreprises qui ne repondent pas.', 'Response time messages GMB < 24h. Penalite si non reponse', 'gmaps', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('TIKTOK_1: Le duet/stitch avec des videos virales surfent sur la vague existante. Plus facile que creer sa propre viralite.', 'Duet/stitch viral = surfer vague existante. Plus facile', 'tiktok_comments', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('TIKTOK_2: Le story time (raconter une anecdote face camera) est le format le plus simple et le plus engageant.', 'TikTok story time face camera = simple + engageant', 'tiktok_comments', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('TIKTOK_3: Les 3 premiers mots du texte sur la video determinent si le viewer s arrete de scroller.', 'TikTok: 3 premiers mots texte = arret scroll ou non', 'tiktok_comments', 'insight', 0.85, 'massive_boost_44b', 'system'),
('TIKTOK_4: Le reply to comment (repondre a un commentaire avec une video) est le hack de croissance #1 sur TikTok.', 'Reply to comment video = hack croissance #1 TikTok', 'tiktok_comments', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('TIKTOK_5: Les hashtags de niche (< 100K videos) ont plus de chances de propulser la video en For You que les hashtags populaires.', 'Hashtags niche < 100K > populaires pour For You', 'tiktok_comments', 'insight', 0.82, 'massive_boost_44b', 'system'),
('LINKEDIN_1: Le document post (PDF/carrousel) a la plus grande portee organique sur LinkedIn en 2026.', 'LinkedIn document/PDF = plus grande portee organique 2026', 'content', 'insight', 0.85, 'massive_boost_44b', 'system'),
('LINKEDIN_2: Le video natif LinkedIn a 5x plus de portee que le lien YouTube partage sur LinkedIn.', 'Video native LinkedIn = 5x portee vs lien YouTube', 'content', 'insight', 0.85, 'massive_boost_44b', 'system'),
('LINKEDIN_3: Le optimal posting time LinkedIn France: mardi-jeudi, 7h30-9h00 ou 12h-13h00.', 'LinkedIn FR: mardi-jeudi, 7h30-9h ou 12h-13h', 'content', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('LINKEDIN_4: Les polls LinkedIn ont la plus grande portee mais le plus faible engagement significatif. Utiliser avec parcimonie.', 'LinkedIn polls: portee max mais engagement faible. Parcimonie', 'content', 'insight', 0.80, 'massive_boost_44b', 'system'),
('LINKEDIN_5: Le LinkedIn newsletter (article newsletter) atteint 40% de taux d ouverture vs 20% email classique.', 'LinkedIn newsletter = 40% OR vs 20% email classique', 'content', 'insight', 0.80, 'massive_boost_44b', 'system'),
('SEO_LOCAL_1: Le Google Business Profile (ex GMB) est le facteur #1 pour le pack local (3 resultats avec carte).', 'GBP = facteur #1 pack local', 'gmaps', 'best_practice', 0.90, 'massive_boost_44b', 'system'),
('SEO_LOCAL_2: Les citations NAP (Name, Address, Phone) coherentes sur 50+ annuaires boostent le ranking local.', 'Citations NAP 50+ annuaires = boost ranking local', 'gmaps', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('SEO_LOCAL_3: Les avis Google recent et frequent sont un signal de ranking fort. Demander 5+ avis par mois.', 'Avis Google 5+/mois = signal ranking fort', 'gmaps', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('SEO_LOCAL_4: Le schema markup LocalBusiness augmente les chances d apparaitre dans les rich results locaux.', 'Schema LocalBusiness = rich results locaux', 'seo', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('SEO_LOCAL_5: Les pages locales dediees (1 page par ville desservie) augmentent le trafic local de 30%.', 'Pages locales par ville = +30% trafic local', 'seo', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('FINANCE_1: Le unit economics positif (chaque client genere plus qu il coute) est le prerequis avant de scaler.', 'Unit economics positif avant scaler', 'comptable', 'best_practice', 0.90, 'massive_boost_44b', 'system'),
('FINANCE_2: Le gross margin target pour un SaaS: > 70%. En dessous, les couts de serveur/API sont trop eleves.', 'Gross margin SaaS > 70%. Sinon couts serveur/API trop hauts', 'comptable', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('FINANCE_3: Le R&D vs S&M ratio: en early stage 70% R&D 30% S&M. En growth 40% R&D 60% S&M.', 'R&D/S&M: early 70/30, growth 40/60', 'comptable', 'insight', 0.78, 'massive_boost_44b', 'system'),
('FINANCE_4: Le operating cash flow (cash genere par les operations) doit etre positif avant la Series B.', 'Operating cash flow positif avant Series B', 'comptable', 'insight', 0.78, 'massive_boost_44b', 'system'),
('FINANCE_5: Le EBITDA margin target pour un SaaS mature: > 20%. Les meilleurs SaaS atteignent 30-40%.', 'EBITDA margin SaaS mature > 20%. Top 30-40%', 'comptable', 'insight', 0.78, 'massive_boost_44b', 'system')
ON CONFLICT DO NOTHING;
-- ═══ ELITE CONTENT AGENT — 100 learnings niveau expert 50 ans ═══
-- Agent: content (stratégie contenu, publications, calendrier)
-- Expertise: content marketing, storytelling, viralité, algorithmes sociaux

INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('CONTENT_ELITE: Le hook ideal suit le schema DISRUPT: Dissonance cognitive (ce que tu crois est faux) → Intrigue → Specificite → Tension → Urgence → Resolution → Proof.', 'DISRUPT hook framework: dissonance → intrigue → specificite → tension → urgence → resolution → proof', 'content', 'best_practice', 0.92, 'elite_content', 'system'),
('CONTENT_ELITE: Le content-market fit existe: le format + la plateforme + le message doivent etre alignes. Un bon message dans le mauvais format echoue.', 'Content-market fit: format + plateforme + message alignes', 'content', 'insight', 0.90, 'elite_content', 'system'),
('CONTENT_ELITE: Le biais de recence algorithmique: publier quand l audience est en ligne ET quand la competition est faible (creneaux sous-exploites).', 'Biais recence algo: publier quand audience active + competition faible', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: La repartition 3-1-1: 3 posts de valeur pure, 1 post d engagement (question, poll), 1 post promotionnel. Ce ratio maximise la confiance.', 'Ratio 3-1-1: 3 valeur, 1 engagement, 1 promo = max confiance', 'content', 'best_practice', 0.90, 'elite_content', 'system'),
('CONTENT_ELITE: Le open loop dans les carrousels (teaser de la conclusion sur la slide 1) force le swipe et multiplie les completions par 3.', 'Open loop carrousel: teaser conclusion slide 1 = 3x completions', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le pattern interrupt algorithmique: changer de format tous les 3-4 posts (texte → video → carrousel → image) empeche l algo de reduire la portee.', 'Varier format 3-4 posts = empecher reduction portee algo', 'content', 'best_practice', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le content velocity: la vitesse de publication dans les 30 premieres minutes determine 80% de la portee finale. Mobiliser l engagement immediatement.', 'Content velocity 30 min = 80% portee finale. Engagement immediat', 'content', 'insight', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le narrative arc en 5 temps pour les posts longs: situation → complication → tension → resolution → morale. Chaque etape retient le lecteur.', 'Narrative arc 5 temps: situation → complication → tension → resolution → morale', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Les emotions primaires dans l ordre de partageabilite: 1) surprise, 2) admiration, 3) colere, 4) peur, 5) joie. La surprise est le trigger #1.', 'Emotions partage: surprise > admiration > colere > peur > joie', 'content', 'insight', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le content stacking: publier 3 contenus lies le meme jour sur 3 plateformes differentes cree un effet de masse et amplifie la portee cross-platform.', 'Content stacking: 3 contenus lies meme jour 3 plateformes = amplification', 'content', 'best_practice', 0.82, 'elite_content', 'system'),
('CONTENT_ELITE: Le algorithme Instagram 2026 utilise 4 signaux principaux dans l ordre: 1) watch time/saves, 2) shares via DM, 3) comments, 4) likes. Optimiser pour les saves.', 'IG 2026 algo: watch time/saves > shares DM > comments > likes', 'content', 'insight', 0.90, 'elite_content', 'system'),
('CONTENT_ELITE: Le algorithme TikTok For You 2026: 1) completion rate, 2) rewatches, 3) shares, 4) comments, 5) follows from video. Le rewatch est le signal le plus puissant.', 'TikTok 2026 FYP: completion > rewatch > shares > comments > follows', 'content', 'insight', 0.90, 'elite_content', 'system'),
('CONTENT_ELITE: Le algorithme LinkedIn 2026 pondere: 1) dwell time (temps de lecture), 2) meaningful comments (5+ mots), 3) reshares, 4) reactions.', 'LinkedIn 2026 algo: dwell time > meaningful comments > reshares > reactions', 'content', 'insight', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le content pillar mapping: definir 3-5 piliers de contenu (sujets cles), chaque pilier ayant 10-15 sous-sujets. Tourner entre les piliers.', 'Content pillars: 3-5 piliers × 10-15 sous-sujets. Rotation', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le storytelling en milieu professionnel: toujours inclure 1 moment de vulnerabilite. L imperfection connecte 3x plus que la perfection.', 'Vulnerabilite dans storytelling = 3x connexion vs perfection', 'content', 'insight', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le content compounding: les articles evergreen generent du trafic cumulatif. 1 article de qualite = trafic croissant pendant 2-3 ans.', 'Content compounding: 1 article evergreen = trafic croissant 2-3 ans', 'content', 'insight', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le semantic richness: les contenus qui utilisent des synonymes, des champs lexicaux riches et du vocabulaire varie rankent 15% mieux en SEO.', 'Semantic richness: vocabulaire varie = +15% ranking SEO', 'content', 'insight', 0.82, 'elite_content', 'system'),
('CONTENT_ELITE: Le personal story framework pour les posts: 1 fait (ce qui s est passe), 1 feeling (ce que j ai ressenti), 1 finding (ce que j ai appris).', 'Personal story: 1 fait + 1 feeling + 1 finding', 'content', 'best_practice', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le caption engineering sur IG: premiere phrase = hook (arreter le scroll), derniere phrase = CTA + appel a l action. Le milieu = valeur.', 'Caption IG: hook debut + valeur milieu + CTA fin', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le concept de content-audience flywheel: plus l audience grandit → plus de feedback → meilleur contenu → plus d audience. Iterer vite.', 'Content-audience flywheel: audience → feedback → meilleur contenu → audience', 'content', 'insight', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le snackable-to-deep funnel: contenu court (Reels, tweets) pour attirer → contenu long (blog, podcast) pour convertir → contenu exclusif pour retenir.', 'Funnel contenu: court (attirer) → long (convertir) → exclusif (retenir)', 'content', 'best_practice', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le timing precision par plateforme FR: LinkedIn 7h30-8h30, Instagram 12h-13h et 19h-21h, TikTok 11h-13h et 19h-22h, X 8h-9h et 18h-19h.', 'Timing FR: LI 7h30, IG 12h+19h, TT 11h+19h, X 8h+18h', 'content', 'best_practice', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le repost strategy: re-publier les meilleurs contenus 3-6 mois plus tard avec une mise a jour. 70% de l audience n a pas vu le premier.', 'Repost 3-6 mois + MAJ: 70% audience n a pas vu le premier', 'content', 'best_practice', 0.82, 'elite_content', 'system'),
('CONTENT_ELITE: Le content debt: comme la dette technique, les contenus obsoletes non mis a jour degradent la credibilite. Auditer trimestriellement.', 'Content debt: contenus obsoletes = credibilite degradee. Audit trimestriel', 'content', 'insight', 0.82, 'elite_content', 'system'),
('CONTENT_ELITE: Le vanity metrics trap: les likes ne correlent pas avec les ventes. Les saves et les partages sont les vrais indicateurs de valeur.', 'Vanity metrics: likes ≠ ventes. Saves + partages = vrais indicateurs', 'content', 'insight', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le content moat: la voix unique (ton, style, perspective) est inimitable par les concurrents. C est le seul avantage durable en contenu.', 'Content moat: voix unique = seul avantage durable inimitable', 'content', 'insight', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le audience-first creation: demander a l audience ce qu elle veut (sondages, commentaires) puis creer ce contenu. 100% product-market fit.', 'Audience-first: demander puis creer = 100% content-market fit', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le content ecosystem: chaque plateforme a un role. LinkedIn = credibilite. Instagram = communaute. TikTok = decouverte. Blog = SEO. Newsletter = retention.', 'Content ecosystem: LI credibilite, IG communaute, TT decouverte, blog SEO, newsletter retention', 'content', 'best_practice', 0.90, 'elite_content', 'system'),
('CONTENT_ELITE: Le micro-learning format (1 concept en 60s) est le format le plus save-able sur toutes les plateformes. Ideal pour le contenu educatif.', 'Micro-learning 1 concept 60s = plus save-able toutes plateformes', 'content', 'insight', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le content production system: 1 jour par semaine dedie a la creation (batch) → planification automatique → publication auto → analyse → iteration.', 'Content system: 1 jour batch → auto-planification → auto-publication → analyse → iteration', 'content', 'best_practice', 0.85, 'elite_content', 'system')
ON CONFLICT DO NOTHING;
-- ═══ ELITE COMMERCIAL AGENT — 100 learnings niveau expert 50 ans ═══
-- Agent: commercial (vente, prospection, CRM, closing)
-- Expertise: vente B2B/B2C, negociation, pipeline management, psychologie de vente

INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('COMMERCIAL_ELITE: Le top closer ne vend pas. Il diagnostique. 80% du temps de vente doit etre passe a ecouter et poser des questions.', 'Top closer: 80% ecouter, 20% presenter. Diagnostiquer pas vendre', 'commercial', 'best_practice', 0.92, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le triangle de la vente: Timing × Trust × Tension. Les 3 doivent etre alignes pour closer. Si 1 manque, le deal est mort.', 'Triangle vente: Timing × Trust × Tension. 3 alignes sinon mort', 'commercial', 'insight', 0.90, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le multi-threading avance: contacter 3-5 stakeholders dans le meme compte. Si 1 champion part, le deal survit.', 'Multi-threading 3-5 stakeholders = deal survit si champion part', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le pricing anchoring: toujours presenter l option la plus chere en premier. Elle ancre la perception de valeur pour toutes les options suivantes.', 'Pricing anchoring: option chere en premier = ancrer valeur', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le objection anticipation: adresser les 3 objections principales AVANT que le prospect ne les pose. Cela desactive la resistance.', 'Anticiper 3 objections = desactiver resistance avant qu elle ne se forme', 'commercial', 'best_practice', 0.90, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le deal qualification MEDDICC: Metrics, Economic buyer, Decision criteria, Decision process, Identify pain, Champion, Competition. Si Competition est forte, pivoter.', 'MEDDICC: Metrics, Economic buyer, Decision, Pain, Champion, Competition', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le pipeline velocity formula: (# deals × avg deal size × win rate) / avg sales cycle length. Optimiser chaque variable independamment.', 'Pipeline velocity: deals × size × win% / cycle length. Optimiser chaque var', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le champion test: si votre champion ne peut pas expliquer votre proposition de valeur en 30 secondes a son boss, le deal est a risque.', 'Champion test: champion explique value prop en 30s a son boss sinon risque', 'commercial', 'insight', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le negative reverse selling (Chris Voss): dire "vous avez probablement raison, ce n est peut-etre pas le bon moment" pousse le prospect a se convaincre lui-meme.', 'Negative reverse selling: dire pas bon moment → prospect se convainc', 'commercial', 'best_practice', 0.82, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le decision mapping: identifier qui decide (economic buyer), qui influence (champion), qui bloque (detracteur), qui valide (legal, IT). Strategie pour chacun.', 'Decision mapping: decide + influence + bloque + valide. Strategie chacun', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le urgency creation sans manipulation: "quelles consequences si vous ne resolvez pas ce probleme dans les 3 prochains mois?" Quantifier le cout de l inaction.', 'Urgence ethique: quantifier cout de l inaction sur 3 mois', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le deal review framework: chaque vendredi, revoir les 5 deals les plus importants avec le framework: next step? blocage? risk level? action requise?', 'Deal review vendredi: 5 deals, next step + blocage + risk + action', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le discovery call structure: 5 min rapport, 5 min contexte (leur situation), 10 min probleme (creuser), 5 min impact (quantifier), 5 min next step.', 'Discovery call: rapport 5 + contexte 5 + probleme 10 + impact 5 + next 5', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le trigger event selling: suivre les signaux d achat (levee de fonds, recrutement, changement de direction, lancement) et contacter dans les 48h.', 'Trigger events: levee/recrutement/direction/lancement → contacter 48h', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le mutual close plan: documenter avec le prospect les etapes restantes, les responsables, et les dates. Partager dans un doc collaboratif.', 'Mutual close plan: etapes + responsables + dates dans doc collaboratif', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le cost of inaction (COI) framework: calculer combien le prospect perd par mois en ne resolvant pas son probleme. Plus puissant que le ROI.', 'COI framework: calculer perte/mois sans solution. Plus puissant que ROI', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le land and expand strategy: commencer petit (1 equipe, 1 use case) puis expander a toute l entreprise une fois la valeur prouvee.', 'Land & expand: petit debut → prouver valeur → expansion entreprise', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le competitive displacement: ne jamais critiquer le concurrent. Demander au prospect ce qui pourrait etre mieux puis montrer comment vous excellez la-dessus.', 'Competitive displacement: jamais critiquer. Demander mieux puis montrer excellence', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le proposal structure gagnante: 1) recap du probleme (montrer qu on a ecoute), 2) solution (comment), 3) resultats attendus (chiffres), 4) prix, 5) next steps.', 'Proposal: probleme recap → solution → resultats chiffres → prix → next steps', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le commercial scoring avance: score = (budget confirme×3 + decision maker engage×3 + timeline definie×2 + besoin valide×2) / 10. Score > 7 = deal chaud.', 'Commercial scoring: (budget×3 + DM×3 + timeline×2 + besoin×2)/10. >7 = chaud', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le closing technique soft: "sur la base de ce qu on a discute, est-ce que vous voyez quelque chose qui vous empecherait d avancer?" Laisser le silence.', 'Soft close: voyez-vous obstacle? + silence', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le risk reversal: garantie 30 jours, SLA engage, pilot gratuit, paiement apres resultats. Eliminer tout risque pour le prospect.', 'Risk reversal: garantie + SLA + pilot + paiement apres resultats = 0 risque', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le social selling index optimal: poster 3x/semaine, commenter 5x/jour, envoyer 5 DMs personnalises/jour, partager 2x/semaine. SSI > 80 en 90 jours.', 'Social selling: poster 3x/sem + 5 commentaires/jour + 5 DM/jour = SSI 80 en 90j', 'commercial', 'best_practice', 0.82, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le pipeline coverage ratio ideal: 3x le quota pour les deals < 30j, 4x pour 30-60j, 5x pour 60-90j. En dessous = risque de quota miss.', 'Pipeline coverage: 3x <30j, 4x 30-60j, 5x 60-90j. Sinon risque quota miss', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le cold email expert: 1 phrase perso (montrer qu on a cherche), 1 phrase valeur (probleme specifique resolu), 1 phrase CTA (question simple). Max 80 mots.', 'Cold email: 1 perso + 1 valeur + 1 CTA. Max 80 mots', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le follow-up timing science: email J+2 (mardi), call J+4 (jeudi), LinkedIn J+6 (lundi), email J+9, breakup J+14. Jamais le meme canal consecutif.', 'Follow-up: email J2, call J4, LinkedIn J6, email J9, breakup J14. Varier canaux', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le negotiation framework ZOPA: identifier la zone d accord possible (votre minimum et le maximum du prospect). Le deal se fait dans cette zone.', 'ZOPA: zone accord entre votre min et leur max. Deal dans cette zone', 'commercial', 'best_practice', 0.82, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le value engineering: quantifier la valeur en euros (economie de temps × taux horaire × nombre d employes × 12 mois). Presenter ce chiffre avant le prix.', 'Value engineering: economie temps × taux horaire × employes × 12 mois. Avant prix', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le dead deal resurrection: relancer les deals perdus apres 90 jours avec un angle different (nouveau feature, nouveau case study, changement de prix). 10% convertissent.', 'Dead deal resurrection 90j + nouvel angle = 10% conversion', 'commercial', 'insight', 0.82, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le customer as closer: faire intervenir un client satisfait (reference call) dans les deals strategiques. Taux de closing +40%.', 'Reference call client satisfait = +40% closing', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system')
ON CONFLICT DO NOTHING;
-- ═══ ELITE EMAIL + SEO + ADS AGENTS — 90 learnings niveau expert 50 ans ═══

INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
-- EMAIL ELITE (HUGO) - 30 learnings
('EMAIL_ELITE: Le send time personalization (STP): analyser l heure d ouverture de chaque contact et envoyer a SON heure optimale. +20% OR.', 'STP: envoyer a l heure optimale PAR contact = +20% OR', 'email', 'best_practice', 0.90, 'elite_email', 'system'),
('EMAIL_ELITE: Le email rendering test: toujours tester sur Gmail, Outlook, Apple Mail, et mobile. 50% des emails sont ouverts sur mobile.', 'Tester rendering: Gmail + Outlook + Apple Mail + mobile. 50% mobile', 'email', 'best_practice', 0.90, 'elite_email', 'system'),
('EMAIL_ELITE: Le inbox placement rate (IPR) est plus important que le delivery rate. L email peut etre delivre mais en spam.', 'IPR > delivery rate. Delivre ≠ inbox', 'email', 'insight', 0.88, 'elite_email', 'system'),
('EMAIL_ELITE: Le sender reputation score (SenderScore.org) doit etre > 80. En dessous, les emails atterrissent en spam.', 'Sender reputation > 80. Sinon spam', 'email', 'best_practice', 0.88, 'elite_email', 'system'),
('EMAIL_ELITE: Le email warm-up progressif pour un nouveau domaine: semaine 1=20/jour, sem 2=50, sem 3=100, sem 4=200. Toujours avec engagement.', 'Warm-up: S1=20, S2=50, S3=100, S4=200/jour avec engagement', 'email', 'best_practice', 0.88, 'elite_email', 'system'),
('EMAIL_ELITE: Le list hygiene avance: supprimer les hard bounces immediatement, les soft bounces apres 3 tentatives, les inactifs 90j apres reactivation echouee.', 'List hygiene: hard bounce=suppr, soft=3 tries, inactifs 90j apres reactivation', 'email', 'best_practice', 0.88, 'elite_email', 'system'),
('EMAIL_ELITE: Le dynamic content engine: 1 email, N variations de contenu basees sur le segment. Le destinataire recoit un email ultra-personalise.', 'Dynamic content: 1 email N variations par segment = hyper-personnalise', 'email', 'best_practice', 0.85, 'elite_email', 'system'),
('EMAIL_ELITE: Le emotional subject line mapping: curiosite > urgence > vanite > peur > exclusivite. Varier les emotions par campagne.', 'Subject emotions: curiosite > urgence > vanite > peur > exclusivite', 'email', 'insight', 0.82, 'elite_email', 'system'),
('EMAIL_ELITE: Le email cadence optimization: mesurer le unsub rate par frequence. Le sweet spot est le maximum d envois avec < 0.3% unsub rate.', 'Cadence: max envois avec < 0.3% unsub = sweet spot', 'email', 'best_practice', 0.85, 'elite_email', 'system'),
('EMAIL_ELITE: Le email revenue attribution: tracker le revenu genere par chaque email pour identifier les sequences les plus rentables.', 'Email revenue attribution: revenu par email = identifier plus rentables', 'email', 'best_practice', 0.85, 'elite_email', 'system'),
('EMAIL_ELITE: Le re-permission campaign: demander aux contacts inactifs s ils veulent rester abonnes. Nettoie la liste et ameliore la delivrabilite.', 'Re-permission inactifs: veulent rester? Nettoie + delivrabilite', 'email', 'best_practice', 0.82, 'elite_email', 'system'),
('EMAIL_ELITE: Le email A/B test avance: tester 1 variable (sujet, from name, send time, CTA, contenu) avec 10% de la liste, envoyer le gagnant aux 90%.', 'A/B test: 1 variable, 10% test → gagnant aux 90%', 'email', 'best_practice', 0.85, 'elite_email', 'system'),
('EMAIL_ELITE: Le BIMI (Brand Indicators for Message Identification) affiche le logo de la marque dans Gmail. Augmente l OR de 10%.', 'BIMI: logo marque Gmail = +10% OR', 'email', 'insight', 0.80, 'elite_email', 'system'),
('EMAIL_ELITE: La delivrabilite optimale necessite: SPF+DKIM+DMARC+BIMI+rDNS+dedicated IP+warm-up+list hygiene. Tous obligatoires.', 'Delivrabilite: SPF+DKIM+DMARC+BIMI+rDNS+IP dedicace+warmup+hygiene', 'email', 'best_practice', 0.90, 'elite_email', 'system'),
('EMAIL_ELITE: Le plain text email paradox: les emails sans HTML (texte simple) ont un taux de reponse 2x superieur car ils semblent personnels.', 'Plain text email = 2x reponse car semble personnel', 'email', 'insight', 0.82, 'elite_email', 'system'),
-- SEO ELITE - 30 learnings
('SEO_ELITE: Le topical authority est le facteur SEO #1 en 2026. Couvrir un sujet en profondeur (30+ articles lies) surpasse la puissance des backlinks.', 'Topical authority 30+ articles > backlinks en 2026', 'seo', 'insight', 0.90, 'elite_seo', 'system'),
('SEO_ELITE: Le semantic SEO: ne plus cibler 1 mot-cle par page mais 1 sujet complet avec toutes les intentions de recherche (informationnelle, transactionnelle, navigationnelle).', 'Semantic SEO: 1 sujet complet toutes intentions > 1 mot-cle', 'seo', 'best_practice', 0.90, 'elite_seo', 'system'),
('SEO_ELITE: Le content freshness signal: mettre a jour les articles top-performing tous les 3-6 mois avec des donnees recentes. Google favorise le contenu frais.', 'Content freshness: MAJ top articles 3-6 mois. Google favorise frais', 'seo', 'best_practice', 0.88, 'elite_seo', 'system'),
('SEO_ELITE: Le internal linking avance: utiliser des anchor texts descriptifs (pas "cliquez ici"), lier les pages de haute autorite aux nouvelles pages.', 'Internal linking: anchors descriptifs + haute autorite → nouvelles pages', 'seo', 'best_practice', 0.88, 'elite_seo', 'system'),
('SEO_ELITE: Le keyword gap analysis: identifier les mots-cles ou les concurrents rankent et pas vous. Ce sont vos opportunites les plus faciles.', 'Keyword gap: concurrents rankent, pas vous = opportunites faciles', 'seo', 'best_practice', 0.88, 'elite_seo', 'system'),
('SEO_ELITE: Le SERP feature targeting: identifier quels rich results (featured snippet, PAA, video, image) apparaissent pour chaque requete et optimiser pour.', 'SERP feature targeting: identifier rich results par requete + optimiser', 'seo', 'best_practice', 0.85, 'elite_seo', 'system'),
('SEO_ELITE: Le page experience signals: LCP < 2.5s, FID < 100ms, CLS < 0.1, HTTPS, no intrusive interstitials. Tous sont des facteurs de ranking.', 'Page experience: LCP<2.5s, FID<100ms, CLS<0.1, HTTPS, no interstitials', 'seo', 'best_practice', 0.90, 'elite_seo', 'system'),
('SEO_ELITE: Le link earning (pas link building): creer du contenu tellement bon que les gens linkent naturellement. Etudes, outils gratuits, infographies.', 'Link earning: contenu exceptionnel = liens naturels. Etudes + outils + infographies', 'seo', 'best_practice', 0.88, 'elite_seo', 'system'),
('SEO_ELITE: Le programmatic SEO: creer des milliers de pages automatiquement pour des requetes longue traine (ville + service, comparatif + produit).', 'Programmatic SEO: milliers de pages auto pour longue traine', 'seo', 'insight', 0.82, 'elite_seo', 'system'),
('SEO_ELITE: Le Search Console avance: analyser les requetes avec impressions > 100 et CTR < 2%. Ce sont des opportunites d optimisation rapide.', 'GSC: impressions >100 + CTR <2% = optimisation rapide', 'seo', 'best_practice', 0.88, 'elite_seo', 'system'),
('SEO_ELITE: Le Google SGE (Search Generative Experience) en 2026: les sites cites dans les reponses IA captent 30% du trafic. Optimiser pour etre cite.', 'Google SGE 2026: sites cites dans IA = 30% trafic. Optimiser pour citation', 'seo', 'insight', 0.85, 'elite_seo', 'system'),
('SEO_ELITE: Le E-E-A-T avance: Experience (vecu personnel), Expertise (competence demontree), Autorite (reconnu par les pairs), Trust (fiable). Tous dans le contenu.', 'EEAT: Experience + Expertise + Autorite + Trust. Tous dans le contenu', 'seo', 'best_practice', 0.90, 'elite_seo', 'system'),
('SEO_ELITE: Le zero-click search: 65% des recherches Google n aboutissent a aucun clic. Optimiser pour la visibilite (featured snippet, knowledge panel) pas juste le clic.', 'Zero-click 65%: optimiser pour visibilite (snippet, knowledge panel)', 'seo', 'insight', 0.85, 'elite_seo', 'system'),
('SEO_ELITE: Le content pruning: supprimer ou fusionner les pages avec 0 trafic depuis 12 mois. Cela ameliore la qualite moyenne du site et le crawl budget.', 'Content pruning: 0 trafic 12 mois = supprimer/fusionner. Meilleur qualite + crawl', 'seo', 'best_practice', 0.85, 'elite_seo', 'system'),
('SEO_ELITE: Le local SEO avance: schema LocalBusiness + NAP coherent + avis Google + Google Posts + service area + categories = pack local domine.', 'Local SEO: schema + NAP + avis + posts + area + categories = dominer pack local', 'seo', 'best_practice', 0.88, 'elite_seo', 'system'),
-- ADS ELITE - 30 learnings
('ADS_ELITE: Le creative testing framework elite: tester le hook (0-3s), le body (message/angle), le format (UGC/pro/meme), le CTA separement. Pas tout a la fois.', 'Testing elite: hook + body + format + CTA separement', 'ads', 'best_practice', 0.90, 'elite_ads', 'system'),
('ADS_ELITE: Le cost per acquisition target doit etre < 1/3 de la LTV. Si CAC = 100€ et LTV = 300€, le ratio est sain. Au-dela, danger.', 'CPA target < LTV/3. CAC 100 + LTV 300 = sain', 'ads', 'best_practice', 0.88, 'elite_ads', 'system'),
('ADS_ELITE: Le winning ad anatomy (Meta): visual hook 0-2s + problem statement 2-5s + solution 5-10s + social proof 10-12s + CTA 12-15s.', 'Winning ad Meta: hook 0-2s + probleme 2-5s + solution 5-10s + proof 10-12s + CTA 12-15s', 'ads', 'best_practice', 0.88, 'elite_ads', 'system'),
('ADS_ELITE: Le broad targeting avec creative diversification outperforms le targeting precis en 2026 grace au machine learning Meta.', 'Broad targeting + creative diversification > ciblage precis 2026', 'ads', 'insight', 0.85, 'elite_ads', 'system'),
('ADS_ELITE: Le ad spend pacing: depenser 50% du budget mensuel en semaine 1-2 (tester), puis concentrer 50% sur les gagnants en semaine 3-4.', 'Pacing: 50% budget S1-2 tester, 50% S3-4 gagnants', 'ads', 'best_practice', 0.82, 'elite_ads', 'system'),
('ADS_ELITE: Le conversion API (CAPI) Meta: envoyer les conversions serveur-a-serveur en complement du pixel. Ameliore le tracking post-iOS 14 de 30%.', 'CAPI Meta serveur-a-serveur = +30% tracking post-iOS 14', 'ads', 'best_practice', 0.88, 'elite_ads', 'system'),
('ADS_ELITE: Le creative fatigue timeline: les UGC fatiguent en 7-10 jours, les creatives pro en 14-21 jours. Avoir un pipeline de creatives fraiches.', 'Creative fatigue: UGC 7-10j, pro 14-21j. Pipeline frais obligatoire', 'ads', 'insight', 0.85, 'elite_ads', 'system'),
('ADS_ELITE: Le Google Ads quality score impacte directement le CPC: QS 10 = CPC 50% moins cher vs QS 5. Optimiser landing page + ad relevance + expected CTR.', 'Google QS 10 = -50% CPC vs QS 5. Landing + relevance + CTR', 'ads', 'best_practice', 0.88, 'elite_ads', 'system'),
('ADS_ELITE: Le retargeting layers: J1-3 = offre directe (plus chaud), J4-7 = temoignage/social proof, J8-14 = contenu educatif, J15-30 = offre speciale.', 'Retargeting layers: J1-3 offre, J4-7 proof, J8-14 educatif, J15-30 offre speciale', 'ads', 'best_practice', 0.85, 'elite_ads', 'system'),
('ADS_ELITE: Le full-funnel attribution: TOFU (video views, reach) est mesure en CPM et brand lift. MOFU en CPC et CTR. BOFU en CPA et ROAS.', 'Attribution full-funnel: TOFU CPM/brand lift, MOFU CPC/CTR, BOFU CPA/ROAS', 'ads', 'best_practice', 0.85, 'elite_ads', 'system'),
('ADS_ELITE: Le audience segmentation avance: cold (jamais visite), warm (visite site < 30j), hot (ajout panier < 7j), customer (acheteur). Budget et message differents.', 'Audience: cold/warm/hot/customer. Budget et message differents par segment', 'ads', 'best_practice', 0.88, 'elite_ads', 'system'),
('ADS_ELITE: Le breakeven ROAS: pour une marge de 60%, le breakeven ROAS est 1.67x (1/0.60). En dessous on perd de l argent. Au-dessus on est rentable.', 'Breakeven ROAS = 1/marge. Marge 60% = ROAS 1.67x minimum', 'ads', 'best_practice', 0.88, 'elite_ads', 'system'),
('ADS_ELITE: Le TikTok Spark Ads (booster un post organique existant) performent 30% mieux que les ads creees from scratch sur TikTok.', 'TikTok Spark Ads booster organique = +30% vs ads from scratch', 'ads', 'insight', 0.82, 'elite_ads', 'system'),
('ADS_ELITE: Le media buying seasonality: les CPMs sont 2-3x plus chers en Q4 (Black Friday, Noel). Planifier le budget annuel en consequence.', 'CPMs Q4 = 2-3x plus cher (BF, Noel). Planifier budget annuel', 'ads', 'insight', 0.85, 'elite_ads', 'system'),
('ADS_ELITE: Le performance creative framework: 1) pain point hook → 2) agitate → 3) solution reveal → 4) demo/proof → 5) CTA urgence. Format 15-30s.', 'Creative framework: pain → agitate → solution → proof → CTA. 15-30s', 'ads', 'best_practice', 0.88, 'elite_ads', 'system')
ON CONFLICT DO NOTHING;
-- ═══ ELITE CEO + RETENTION + ONBOARDING + DM + WHATSAPP + CHATBOT + GMAPS + COMPTABLE + RH — 90 learnings ═══

INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
-- CEO ELITE (10)
('CEO_ELITE: Le CEO decision framework: chaque decision passe par 3 filtres: 1) impact sur le client, 2) impact sur le revenu, 3) faisabilite technique. Score 1-5 chacun.', 'CEO decision: impact client × impact revenu × faisabilite. Score 1-5', 'ceo', 'best_practice', 0.92, 'elite_ceo', 'system'),
('CEO_ELITE: Le CEO weekly pulse: 5 metriques a verifier chaque lundi: MRR, new signups, churn, NPS, pipeline. Si 1 est rouge, action immediate.', 'CEO weekly pulse: MRR + signups + churn + NPS + pipeline. Rouge = action', 'ceo', 'best_practice', 0.90, 'elite_ceo', 'system'),
('CEO_ELITE: Le strategic planning cadence: vision 3 ans (annuelle), objectifs 1 an (annuelle), OKRs 90 jours (trimestrielle), sprints 2 semaines.', 'Planning: vision 3 ans → objectifs 1 an → OKR 90j → sprints 2 sem', 'ceo', 'best_practice', 0.88, 'elite_ceo', 'system'),
('CEO_ELITE: Le CEO communication: transparence financiere (partager les chiffres), vulnerabilite controllee (partager les doutes), vision claire (partager le futur).', 'CEO comm: transparence finances + vulnerabilite controlee + vision claire', 'ceo', 'best_practice', 0.85, 'elite_ceo', 'system'),
('CEO_ELITE: Le market intelligence: suivre 5 concurrents, 3 tendances majeures, 2 risques exterieurs chaque mois. Anticiper pas reagir.', 'Market intelligence: 5 concurrents + 3 tendances + 2 risques/mois. Anticiper', 'ceo', 'best_practice', 0.85, 'elite_ceo', 'system'),
('CEO_ELITE: Le resource allocation: 70% sur le core business (ce qui marche), 20% sur les adjacences (extension), 10% sur l innovation (futur).', 'Resource allocation: 70% core + 20% adjacence + 10% innovation', 'ceo', 'best_practice', 0.85, 'elite_ceo', 'system'),
('CEO_ELITE: Le CEO report pour KeiroAI doit etre en 3 sections: ✅ Wins (celebrer), ⚠️ Alerts (agir), 🎯 Focus (prioriser). Max 7 lignes total.', 'CEO report: wins + alerts + focus. Max 7 lignes', 'ceo', 'best_practice', 0.92, 'elite_ceo', 'system'),
('CEO_ELITE: Le cross-agent optimization: si l agent email a un bon taux d ouverture sur un sujet, l agent contenu doit creer du contenu sur ce meme sujet.', 'Cross-agent: email bon sujet → contenu reprend ce sujet', 'ceo', 'best_practice', 0.90, 'elite_ceo', 'system'),
('CEO_ELITE: Le agent performance ranking: classer les agents par ROI (resultats / couts API) chaque semaine. Investir plus dans les performants.', 'Agent ranking ROI hebdo: investir plus dans les performants', 'ceo', 'best_practice', 0.88, 'elite_ceo', 'system'),
('CEO_ELITE: Le cascade intelligence: une tendance detectee par l agent marketing doit etre transmise au contenu, aux ads, au commercial et au SEO en < 1h.', 'Cascade intelligence: tendance marketing → tous agents < 1h', 'ceo', 'best_practice', 0.90, 'elite_ceo', 'system'),
-- RETENTION ELITE (10)
('RETENTION_ELITE: Le cohort-based churn analysis: analyser le churn par semaine d inscription revele quand les clients decrochent (souvent J7, J30, J90).', 'Cohort churn: par semaine inscription. Decrochage J7, J30, J90', 'retention', 'best_practice', 0.88, 'elite_retention', 'system'),
('RETENTION_ELITE: Le save playbook: pour chaque signal de pre-churn, une action automatique. Usage baisse → email education. Ticket ouvert → call CS. Paiement echoue → dunning.', 'Save playbook: usage baisse→email, ticket→call, paiement→dunning', 'retention', 'best_practice', 0.88, 'elite_retention', 'system'),
('RETENTION_ELITE: Le expansion trigger detection: quand un client atteint 80% de son quota, invite des collegues, ou demande une feature premium → proposer l upgrade.', 'Expansion triggers: 80% quota + invite collegues + demande premium → upgrade', 'retention', 'best_practice', 0.85, 'elite_retention', 'system'),
('RETENTION_ELITE: Le net revenue retention (NRR) > 120% signifie que les clients existants generent plus de revenus chaque annee sans nouveaux clients.', 'NRR > 120%: clients existants generent plus chaque annee', 'retention', 'insight', 0.88, 'elite_retention', 'system'),
('RETENTION_ELITE: Le customer health scoring avance: usage score (40%) + engagement score (20%) + support score (20%) + financial score (20%). Alerte si < 60.', 'Health score: usage 40% + engagement 20% + support 20% + financial 20%. Alerte < 60', 'retention', 'best_practice', 0.88, 'elite_retention', 'system'),
-- ONBOARDING ELITE (10)
('ONBOARDING_ELITE: Le aha moment identification: analyser les users qui restent (retenu J30) vs ceux qui partent. La difference = l aha moment a atteindre.', 'Aha moment: analyser retenu J30 vs partis. Difference = aha', 'onboarding', 'best_practice', 0.90, 'elite_onboarding', 'system'),
('ONBOARDING_ELITE: Le time-to-first-value doit etre mesure en secondes, pas en minutes. Pour KeiroAI: premier agent actif < 120 secondes apres signup.', 'TTFV en secondes. KeiroAI: premier agent < 120s apres signup', 'onboarding', 'best_practice', 0.90, 'elite_onboarding', 'system'),
('ONBOARDING_ELITE: Le progressive disclosure: ne montrer que 20% des features au debut. Debloquer les features avancees progressivement selon l usage.', 'Progressive disclosure: 20% features debut. Debloquer selon usage', 'onboarding', 'best_practice', 0.88, 'elite_onboarding', 'system'),
('ONBOARDING_ELITE: Le contextual onboarding: pas de tutoriel generique. Montrer la bonne feature au bon moment quand l utilisateur en a besoin.', 'Contextual onboarding: bonne feature au bon moment = pas tutoriel generique', 'onboarding', 'best_practice', 0.88, 'elite_onboarding', 'system'),
('ONBOARDING_ELITE: Le onboarding friction audit: lister chaque clic, chaque champ, chaque decision entre le signup et le aha moment. Eliminer tout ce qui n est pas essentiel.', 'Friction audit: lister chaque clic signup→aha. Eliminer non-essentiel', 'onboarding', 'best_practice', 0.90, 'elite_onboarding', 'system'),
-- DM ELITE (10)
('DM_ELITE: Le warm outreach system: J-7 liker 3 posts, J-3 commenter avec valeur, J0 reagir a une story, J+1 DM personnalise. Taux reponse 40%.', 'Warm outreach: J-7 liker, J-3 commenter, J0 story, J+1 DM = 40% reponse', 'dm_instagram', 'best_practice', 0.88, 'elite_dm', 'system'),
('DM_ELITE: Le DM personalization framework: 1 compliment specifique (pas generique) + 1 question ouverte liee a leur activite + 0 pitch.', 'DM perso: 1 compliment specifique + 1 question ouverte + 0 pitch', 'dm_instagram', 'best_practice', 0.90, 'elite_dm', 'system'),
('DM_ELITE: Le DM scoring: reactions stories = 5pts, commentaire = 10pts, reponse DM = 20pts, appel = 50pts. Score > 50 = prospect qualifie.', 'DM scoring: story 5, comment 10, reponse DM 20, appel 50. >50 = qualifie', 'dm_instagram', 'best_practice', 0.85, 'elite_dm', 'system'),
('DM_ELITE: Le DM automation safe zone: max 20-30 DMs/jour pour eviter la detection Instagram. Varier les messages. Jamais copier-coller.', 'DM auto safe: 20-30/jour max. Varier messages. 0 copier-coller', 'dm_instagram', 'best_practice', 0.88, 'elite_dm', 'system'),
('DM_ELITE: Le conversion DM framework: apres 3 echanges positifs, proposer un appel de 15 min avec un lien Calendly. Pas de pitch par ecrit.', 'DM conversion: 3 echanges positifs → Calendly 15 min. Jamais pitch ecrit', 'dm_instagram', 'best_practice', 0.85, 'elite_dm', 'system'),
-- WHATSAPP ELITE (10)
('WHATSAPP_ELITE: Le opt-in strategy: proposer le WhatsApp comme canal de suivi apres un achat ou une inscription. Jamais en premier contact.', 'WhatsApp opt-in: proposer apres achat/inscription. Jamais premier contact', 'whatsapp', 'best_practice', 0.90, 'elite_whatsapp', 'system'),
('WHATSAPP_ELITE: Le message template optimization: les templates avec variable de personnalisation (prenom, produit) ont 2x plus de clics.', 'Templates WhatsApp avec variable perso = 2x clics', 'whatsapp', 'insight', 0.85, 'elite_whatsapp', 'system'),
('WHATSAPP_ELITE: Le WhatsApp commerce flow: message template → chatbot qualification → catalogue produit → panier → paiement → confirmation. Tout dans WhatsApp.', 'WhatsApp commerce: template → chatbot → catalogue → panier → paiement → confirm', 'whatsapp', 'best_practice', 0.82, 'elite_whatsapp', 'system'),
('WHATSAPP_ELITE: Le timing WhatsApp business: 9h-12h et 14h-17h en semaine. Jamais apres 20h. Weekend = emergences uniquement.', 'WhatsApp timing: 9-12h et 14-17h semaine. Jamais apres 20h. Weekend = urgences', 'whatsapp', 'best_practice', 0.85, 'elite_whatsapp', 'system'),
('WHATSAPP_ELITE: Le segment broadcast: listes par interet (produit A, produit B), par etape (prospect, client, VIP). Jamais de broadcast generique a tous.', 'WhatsApp broadcast segmente: par interet + etape. Jamais generique a tous', 'whatsapp', 'best_practice', 0.88, 'elite_whatsapp', 'system'),
-- CHATBOT ELITE (10)
('CHATBOT_ELITE: Le conversational design: chaque message du bot doit avoir 1 objectif clair. Si le message a 2 objectifs, le couper en 2.', 'Chatbot: 1 message = 1 objectif. 2 objectifs = couper en 2', 'chatbot', 'best_practice', 0.88, 'elite_chatbot', 'system'),
('CHATBOT_ELITE: Le quick reply buttons (max 3) augmentent le taux de reponse de 40% vs le texte libre. Guider la conversation.', 'Quick reply buttons max 3 = +40% reponse vs texte libre', 'chatbot', 'insight', 0.85, 'elite_chatbot', 'system'),
('CHATBOT_ELITE: Le sentiment detection en temps reel: si le client est frustre (mots negatifs, majuscules, ponctuation multiple), escalader a un humain immediatement.', 'Sentiment detection: frustration (mots negatifs, majuscules) → escalade humaine', 'chatbot', 'best_practice', 0.88, 'elite_chatbot', 'system'),
('CHATBOT_ELITE: Le proactive engagement: declencher le chatbot quand le visiteur est sur la page pricing depuis > 30 secondes ou scroll > 80%.', 'Chatbot proactif: pricing > 30s ou scroll > 80% = declencher', 'chatbot', 'best_practice', 0.82, 'elite_chatbot', 'system'),
('CHATBOT_ELITE: Le chatbot ROI = (tickets evites × cout/ticket) + (leads qualifies × valeur/lead) - cout du chatbot. Doit etre positif en < 3 mois.', 'Chatbot ROI: (tickets evites × cout) + (leads × valeur) - cout. Positif < 3 mois', 'chatbot', 'best_practice', 0.85, 'elite_chatbot', 'system'),
-- GMAPS ELITE (5)
('GMAPS_ELITE: Le review velocity optimization: demander un avis a chaque client satisfait dans les 5 minutes apres la prestation. QR code + lien direct.', 'Review velocity: demander dans 5 min post-prestation. QR + lien direct', 'gmaps', 'best_practice', 0.88, 'elite_gmaps', 'system'),
('GMAPS_ELITE: Le Google Posts strategy: 1 post/semaine alternant: offre, evenement, nouveaute, behind-the-scenes. Chaque post avec CTA + lien.', 'Google Posts: 1/sem alterner offre/event/nouveaute/BTS + CTA + lien', 'gmaps', 'best_practice', 0.85, 'elite_gmaps', 'system'),
('GMAPS_ELITE: Le negative review management: repondre en < 24h avec empathie + solution concrete + invitation a revenir. 30% changent leur note apres une bonne reponse.', 'Avis negatif: < 24h + empathie + solution + invitation = 30% changent note', 'gmaps', 'best_practice', 0.88, 'elite_gmaps', 'system'),
('GMAPS_ELITE: Le GMB optimization checklist: description 750 chars avec mots-cles, 50+ photos, horaires a jour, Q&A pre-remplies, attributs, services avec prix.', 'GMB checklist: description + 50 photos + horaires + Q&A + attributs + prix', 'gmaps', 'best_practice', 0.88, 'elite_gmaps', 'system'),
('GMAPS_ELITE: Le local SEO cross-platform: etre present et coherent sur Google, Apple Maps, Waze, TripAdvisor, Yelp, PagesJaunes. Memes infos partout.', 'SEO local cross-platform: Google + Apple + Waze + TripAdvisor + Yelp + PagesJaunes', 'gmaps', 'best_practice', 0.85, 'elite_gmaps', 'system'),
-- COMPTABLE ELITE (5)
('COMPTABLE_ELITE: Le SaaS metrics dashboard: MRR, ARR, churn, LTV, CAC, LTV/CAC, payback period, gross margin, net dollar retention, runway. Les 10 commandements.', 'SaaS metrics: MRR, ARR, churn, LTV, CAC, ratio, payback, margin, NDR, runway', 'comptable', 'best_practice', 0.90, 'elite_comptable', 'system'),
('COMPTABLE_ELITE: Le cash flow projection 13 semaines (rolling 13-week cash flow) est l outil de gestion tresorerie le plus utile pour les startups.', 'Cash flow projection 13 semaines rolling = outil tresorerie #1 startup', 'comptable', 'best_practice', 0.85, 'elite_comptable', 'system'),
('COMPTABLE_ELITE: Le burn multiple (net burn / net new ARR) < 2 = efficient. 2-4 = acceptable. > 4 = brule trop de cash pour la croissance.', 'Burn multiple: < 2 efficient, 2-4 acceptable, > 4 = trop de burn', 'comptable', 'insight', 0.82, 'elite_comptable', 'system'),
('COMPTABLE_ELITE: Le revenue recognition SaaS: les revenus sont reconnus mensuellement (pas a la signature). Le MRR = ARR/12, pas le cash recu.', 'Revenue recognition SaaS: mensuel pas a la signature. MRR = ARR/12', 'comptable', 'best_practice', 0.85, 'elite_comptable', 'system'),
('COMPTABLE_ELITE: Le unit economics complet: LTV = ARPU × (1/churn rate). CAC = (marketing + sales costs) / new customers. Sain si LTV/CAC > 3.', 'Unit economics: LTV = ARPU/churn. CAC = costs/new customers. LTV/CAC > 3', 'comptable', 'best_practice', 0.88, 'elite_comptable', 'system'),
-- RH ELITE (5)
('RH_ELITE: Le hiring scorecard: definir 3-5 competences cles par poste. Noter chaque candidat 1-5 sur chaque competence. Recruter si moyenne > 4.', 'Hiring scorecard: 3-5 competences notees 1-5. Recruter si > 4', 'rh', 'best_practice', 0.82, 'elite_rh', 'system'),
('RH_ELITE: Le 30-60-90 day plan pour chaque nouvel employe: J30 comprendre, J60 contribuer, J90 performer. Evaluer a chaque milestone.', '30-60-90 plan: J30 comprendre, J60 contribuer, J90 performer', 'rh', 'best_practice', 0.85, 'elite_rh', 'system'),
('RH_ELITE: Le talent density (Netflix): preferer 1 personne exceptionnelle a 2 personnes moyennes. La qualite bat la quantite.', 'Talent density: 1 exceptionnel > 2 moyens. Qualite > quantite', 'rh', 'best_practice', 0.85, 'elite_rh', 'system'),
('RH_ELITE: Le compensation philosophy: payer au percentile 75 du marche attire les meilleurs talents sans exploser le budget.', 'Compensation P75 marche = attirer meilleurs talents sans exploser budget', 'rh', 'best_practice', 0.80, 'elite_rh', 'system'),
('RH_ELITE: Le turnover cost: remplacer un employe coute 6-9 mois de salaire (recrutement + onboarding + perte productivite). La retention est toujours moins chere.', 'Turnover cost: 6-9 mois salaire. Retention toujours moins chere', 'rh', 'insight', 0.85, 'elite_rh', 'system')
ON CONFLICT DO NOTHING;
-- ═══ ELITE MEGA PACK — 200 learnings ultra-spécialisés tous agents ═══

INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
-- CONTENT EXPERT AVANCE (25)
('CONTENT_V2: Le algorithmic amplification hack: poster un commentaire de valeur (50+ mots) sous son propre post dans les 5 premieres minutes booste la portee de 30%.', 'Commenter son post 50+ mots 5 min = +30% portee', 'content', 'best_practice', 0.82, 'elite_v2', 'system'),
('CONTENT_V2: Le content velocity index: nombre de contenus publies × taux d engagement moyen = indicateur d efficacite contenu.', 'Content velocity index: publies × engagement = efficacite', 'content', 'insight', 0.80, 'elite_v2', 'system'),
('CONTENT_V2: Le hook database: maintenir une base de 50+ hooks testes et classes par performance. Reutiliser les gagnants.', 'Hook database 50+ testes et classes. Reutiliser gagnants', 'content', 'best_practice', 0.85, 'elite_v2', 'system'),
('CONTENT_V2: Le format hybride (texte + image + video dans le meme post) a 2x plus d engagement que les formats simples sur LinkedIn.', 'Format hybride texte+image+video LI = 2x engagement', 'content', 'insight', 0.80, 'elite_v2', 'system'),
('CONTENT_V2: Le engagement pod ethique: un groupe de 10-15 createurs qui s engagent mutuellement dans les 30 premieres minutes. +50% portee.', 'Engagement pod 10-15 createurs 30 min = +50% portee', 'content', 'insight', 0.75, 'elite_v2', 'system'),
('CONTENT_V2: Le content recycling: transformer 1 article performant en 5 formats differents (video, infographie, thread, email, podcast clip).', 'Content recycling: 1 article → 5 formats differents', 'content', 'best_practice', 0.85, 'elite_v2', 'system'),
('CONTENT_V2: Le carousel formula IG: slide 1 = hook fort, slides 2-7 = valeur (1 point par slide), slide 8 = recap, slide 9 = CTA + save this.', 'Carousel IG: hook → valeur 1pt/slide → recap → CTA save', 'content', 'best_practice', 0.85, 'elite_v2', 'system'),
('CONTENT_V2: Le SEO content scoring: chaque article doit viser: 1500+ mots, 3+ headings H2/H3, 1+ image, 3+ liens internes, meta < 155 chars.', 'SEO content scoring: 1500 mots + H2/H3 + image + liens internes + meta', 'content', 'best_practice', 0.85, 'elite_v2', 'system'),
('CONTENT_V2: Le brand voice consistency checker: chaque contenu doit passer par un check: ton correct? vocabulaire marque? pas de jargon interdit?', 'Brand voice check: ton + vocabulaire + jargon interdit', 'content', 'best_practice', 0.88, 'elite_v2', 'system'),
('CONTENT_V2: Le seasonal content multiplier: anticiper les events (Noel, rentree, BF) avec du contenu prepare 4-6 semaines avant. Double la portee.', 'Seasonal content 4-6 sem avant = 2x portee', 'content', 'best_practice', 0.82, 'elite_v2', 'system'),
-- COMMERCIAL EXPERT AVANCE (25)
('COMMERCIAL_V2: Le prospect intelligence: avant chaque call, analyser: LinkedIn du prospect, site web, actualites recentes, technologie utilisee (BuiltWith).', 'Prospect intel pre-call: LinkedIn + site + news + tech stack', 'commercial', 'best_practice', 0.88, 'elite_v2', 'system'),
('COMMERCIAL_V2: Le pain quantification: "combien ce probleme vous coute par mois?" Si le prospect ne peut pas repondre, l aider a calculer.', 'Pain quantification: combien coute/mois? Aider a calculer', 'commercial', 'best_practice', 0.88, 'elite_v2', 'system'),
('COMMERCIAL_V2: Le authority mapping: identifier le vrai decision maker (pas toujours le titre le plus eleve). Le budget holder est souvent cache.', 'Authority mapping: vrai decision maker ≠ titre eleve. Budget holder cache', 'commercial', 'insight', 0.85, 'elite_v2', 'system'),
('COMMERCIAL_V2: Le timeline acceleration: creer un evenement (lancement, augmentation prix, fin promo) qui force une decision avant une date.', 'Timeline acceleration: evenement qui force decision avant date', 'commercial', 'best_practice', 0.82, 'elite_v2', 'system'),
('COMMERCIAL_V2: Le competitive battle cards: pour chaque concurrent, 1 page avec: forces, faiblesses, objections communes, reponses gagnantes.', 'Battle cards concurrent: forces + faiblesses + objections + reponses', 'commercial', 'best_practice', 0.85, 'elite_v2', 'system'),
('COMMERCIAL_V2: Le deal momentum indicator: si plus de 7 jours sans interaction avec le prospect, le deal perd 15% de probabilite par jour.', 'Deal momentum: > 7j sans interaction = -15% probabilite/jour', 'commercial', 'insight', 0.82, 'elite_v2', 'system'),
('COMMERCIAL_V2: Le referral at close: demander un referral immediatement apres le closing (le client est au pic de satisfaction).', 'Referral at close: demander immediatement apres closing = pic satisfaction', 'commercial', 'best_practice', 0.85, 'elite_v2', 'system'),
('COMMERCIAL_V2: Le video prospecting: envoyer une video Loom de 60s personnalisee (montrer le site du prospect) a un taux de reponse 3x superieur au text.', 'Video Loom 60s perso = 3x reponse vs texte', 'commercial', 'insight', 0.82, 'elite_v2', 'system'),
('COMMERCIAL_V2: Le qualification rapide BANT: Budget (ont-ils le budget?), Authority (sont-ils le decision maker?), Need (besoin reel?), Timeline (quand?).', 'BANT: Budget + Authority + Need + Timeline. 4 questions critiques', 'commercial', 'best_practice', 0.85, 'elite_v2', 'system'),
('COMMERCIAL_V2: Le objection prevention framework: adresser proactivement les 5 objections les plus frequentes dans la presentation avant qu elles ne soient posees.', 'Objection prevention: adresser 5 objections frequentes proactivement', 'commercial', 'best_practice', 0.85, 'elite_v2', 'system'),
-- EMAIL EXPERT AVANCE (20)
('EMAIL_V2: Le email frequency personalization: adapter la frequence d envoi au comportement de chaque contact (ouvreurs frequents = plus, rares = moins).', 'Frequence email personnalisee par comportement contact', 'email', 'best_practice', 0.85, 'elite_v2', 'system'),
('EMAIL_V2: Le AI-powered subject line optimization: utiliser l IA pour generer 10 variantes puis A/B tester les 2 meilleures sur 10% de la liste.', 'IA subject line: 10 variantes → A/B test 2 meilleures sur 10%', 'email', 'best_practice', 0.82, 'elite_v2', 'system'),
('EMAIL_V2: Le email scoring model: ouverture=1pt, clic=3pts, reponse=10pts, forward=5pts. Score > 20 = prospect chaud.', 'Email scoring: ouvre 1, clic 3, reponse 10, forward 5. >20 = chaud', 'email', 'best_practice', 0.85, 'elite_v2', 'system'),
('EMAIL_V2: Le cold email domain strategy: utiliser un domaine secondaire (get.votredomaine.com) pour proteger la reputation du domaine principal.', 'Cold email: domaine secondaire pour proteger domaine principal', 'email', 'best_practice', 0.85, 'elite_v2', 'system'),
('EMAIL_V2: Le email copy formula 1-2-3: 1 probleme identifie, 2 phrases de solution, 3 mots de CTA. Maximum 5 phrases total.', 'Email copy 1-2-3: 1 probleme + 2 solution + 3 mots CTA. 5 phrases max', 'email', 'best_practice', 0.82, 'elite_v2', 'system'),
('EMAIL_V2: Le inbox competition: le sujet d email est en competition avec 50+ autres emails ce jour-la. Se demarquer est vital.', 'Subject compete avec 50+ emails/jour. Se demarquer vital', 'email', 'insight', 0.85, 'elite_v2', 'system'),
('EMAIL_V2: Le triggered email revenue: abandoned cart (15-20% revenue), welcome series (5-10%), browse abandonment (3-5%), winback (2-3%).', 'Triggered revenue: cart 15-20%, welcome 5-10%, browse 3-5%, winback 2-3%', 'email', 'insight', 0.85, 'elite_v2', 'system'),
('EMAIL_V2: Le email health check mensuel: delivery rate > 95%, open rate > 20%, click rate > 2%, bounce rate < 2%, unsub rate < 0.5%.', 'Email health mensuel: delivery >95%, OR >20%, CTR >2%, bounce <2%, unsub <0.5%', 'email', 'best_practice', 0.88, 'elite_v2', 'system'),
('EMAIL_V2: Le emotional mapping par segment: les prospects froids repondent a la curiosite. Les chauds a l urgence. Les clients a la gratitude.', 'Emotional mapping: froids=curiosite, chauds=urgence, clients=gratitude', 'email', 'insight', 0.82, 'elite_v2', 'system'),
('EMAIL_V2: Le email deliverability stack: SPF + DKIM + DMARC (p=reject) + BIMI + dedicated IP + warmup + feedback loops. Non-negociable.', 'Deliverability stack: SPF+DKIM+DMARC+BIMI+IP dedicace+warmup+FBL', 'email', 'best_practice', 0.90, 'elite_v2', 'system'),
-- SEO EXPERT AVANCE (20)
('SEO_V2: Le keyword clustering: regrouper les mots-cles par intention de recherche et creer 1 page par cluster. Plus efficient que 1 page par mot-cle.', 'Keyword clustering par intention: 1 page/cluster > 1 page/mot-cle', 'seo', 'best_practice', 0.88, 'elite_v2', 'system'),
('SEO_V2: Le search intent analysis: chaque requete a 1 des 4 intents: informational (apprendre), navigational (trouver), transactional (acheter), commercial investigation (comparer).', 'Search intent: informational + navigational + transactional + commercial', 'seo', 'best_practice', 0.88, 'elite_v2', 'system'),
('SEO_V2: Le content gap analysis par URL: comparer les mots-cles de la page #1 sur Google vs votre page. Ajouter les mots-cles manquants.', 'Content gap par URL: mots-cles page #1 vs votre page. Ajouter manquants', 'seo', 'best_practice', 0.85, 'elite_v2', 'system'),
('SEO_V2: Le SERP analysis before writing: analyser les 10 premiers resultats (format, longueur, structure, angles) avant d ecrire. Faire mieux.', 'SERP analysis: analyser top 10 puis faire mieux', 'seo', 'best_practice', 0.88, 'elite_v2', 'system'),
('SEO_V2: Le schema markup avance: FAQ schema (questions/reponses), HowTo schema (tutoriels), Review schema (avis), Product schema (produits).', 'Schema avance: FAQ + HowTo + Review + Product', 'seo', 'best_practice', 0.85, 'elite_v2', 'system'),
('SEO_V2: Le backlink quality metrics: Domain Rating > 40, traffic > 1000/mois, pertinence thematique, pas de spam score. La qualite bat la quantite 10x.', 'Backlink qualite: DR>40 + traffic>1K + pertinent + 0 spam. Qualite 10x > quantite', 'seo', 'best_practice', 0.85, 'elite_v2', 'system'),
('SEO_V2: Le technical SEO audit quarterly: vitesse, indexation, crawl errors, mobile, structured data, canonicals, redirects, internal links.', 'Tech SEO audit trimestriel: vitesse+indexation+crawl+mobile+schema+canonical+redirects+liens', 'seo', 'best_practice', 0.85, 'elite_v2', 'system'),
('SEO_V2: Le organic click-through rate optimization: titre < 60 chars avec mot-cle + power word, meta < 155 chars avec CTA implicite.', 'CTR SERP: titre <60 mot-cle+power word, meta <155 CTA implicite', 'seo', 'best_practice', 0.85, 'elite_v2', 'system'),
('SEO_V2: Le position tracking par mot-cle (SEMrush, Ahrefs): suivre hebdomadairement les positions des 50 mots-cles les plus importants.', 'Position tracking hebdo: 50 mots-cles les plus importants', 'seo', 'best_practice', 0.82, 'elite_v2', 'system'),
('SEO_V2: Le competitor content analysis: identifier les top 20 pages des concurrents par trafic organique. Ce sont vos opportunites de contenu.', 'Competitor content: top 20 pages par trafic = vos opportunites', 'seo', 'best_practice', 0.85, 'elite_v2', 'system'),
-- ADS EXPERT AVANCE (20)
('ADS_V2: Le creative testing velocity: tester 3-5 nouvelles creatives par semaine. Les gagnantes durent 2-4 semaines avant fatigue.', 'Creative velocity: 3-5 nouvelles/semaine. Gagnantes durent 2-4 sem', 'ads', 'best_practice', 0.85, 'elite_v2', 'system'),
('ADS_V2: Le ad angle framework: douleur (montrer le probleme), benefice (montrer le resultat), temoignage (montrer la preuve), valeur (montrer l offre).', 'Ad angles: douleur + benefice + temoignage + valeur', 'ads', 'best_practice', 0.85, 'elite_v2', 'system'),
('ADS_V2: Le budget allocation by funnel stage: 60% BOFU (conversion), 25% MOFU (consideration), 15% TOFU (awareness). Ajuster selon la maturite.', 'Budget funnel: 60% BOFU + 25% MOFU + 15% TOFU', 'ads', 'best_practice', 0.82, 'elite_v2', 'system'),
('ADS_V2: Le ad copy A/B testing hierarchy: headline > CTA > body > image description. Tester dans cet ordre de priorite.', 'A/B test ads: headline > CTA > body > description. Dans cet ordre', 'ads', 'best_practice', 0.82, 'elite_v2', 'system'),
('ADS_V2: Le frequency cap optimal: TOFU 3-5/semaine, MOFU 5-7/semaine, BOFU 7-10/semaine. Plus le prospect est chaud, plus de repetition.', 'Frequency cap: TOFU 3-5, MOFU 5-7, BOFU 7-10/semaine', 'ads', 'best_practice', 0.80, 'elite_v2', 'system'),
('ADS_V2: Le ad reporting template: CPM, CTR, CPC, conversions, CPA, ROAS, frequency, reach, impressions. Par campagne et par creative.', 'Ad reporting: CPM+CTR+CPC+conv+CPA+ROAS+freq+reach+impr par campagne+creative', 'ads', 'best_practice', 0.85, 'elite_v2', 'system'),
('ADS_V2: Le Google Ads script automation: automatiser les bid adjustments, les rapports, les alertes de budget. Gain de temps 80%.', 'Google Ads scripts: auto bid+rapports+alertes = -80% temps', 'ads', 'insight', 0.78, 'elite_v2', 'system'),
('ADS_V2: Le dynamic creative optimization (DCO) Meta: uploader 10 images + 5 textes + 3 CTAs. Meta teste les 150 combinaisons et garde les meilleures.', 'DCO Meta: 10 images + 5 textes + 3 CTAs = 150 combinaisons auto-testees', 'ads', 'best_practice', 0.82, 'elite_v2', 'system'),
('ADS_V2: Le profit-based bidding: definir le ROAS cible base sur la marge produit (pas le revenu). Ex: marge 50% → ROAS cible 2x minimum.', 'Profit-based bidding: ROAS cible base sur marge pas revenu', 'ads', 'best_practice', 0.85, 'elite_v2', 'system'),
('ADS_V2: Le cross-platform attribution: le meme prospect voit souvent des ads sur Meta, Google, et TikTok. L attribution multi-touch revele la vraie contribution.', 'Cross-platform attribution: multi-touch revele vraie contribution', 'ads', 'insight', 0.80, 'elite_v2', 'system'),
-- CEO AVANCE (15)
('CEO_V2: Le agent orchestration matrix: definir les interactions entre agents (contenu→SEO, commercial→email, CEO→tous). Eviter les contradictions.', 'Orchestration matrix: interactions agents definies. 0 contradictions', 'ceo', 'best_practice', 0.92, 'elite_v2', 'system'),
('CEO_V2: Le intelligence fusion: combiner les insights de tous les agents (trends + performance + CRM + SEO) pour des recommandations holistiques.', 'Intelligence fusion: insights tous agents → recommandations holistiques', 'ceo', 'best_practice', 0.90, 'elite_v2', 'system'),
('CEO_V2: Le opportunity scoring: chaque opportunite detectee est scoree: impact potentiel (1-5) × probabilite de succes (1-5) × effort requis (1-5 inverse).', 'Opportunity scoring: impact × probabilite × effort inverse', 'ceo', 'best_practice', 0.85, 'elite_v2', 'system'),
('CEO_V2: Le auto-rebalancing: si un canal sous-performe (ex: email OR en baisse), reallouer les ressources vers les canaux performants automatiquement.', 'Auto-rebalancing: canal sous-performant → reallouer vers performants', 'ceo', 'best_practice', 0.85, 'elite_v2', 'system'),
('CEO_V2: Le predictive alerts: detecter les tendances negatives (churn en hausse, engagement en baisse) 2 semaines avant qu elles n impactent le revenu.', 'Predictive alerts: tendances negatives 2 sem avant impact revenu', 'ceo', 'best_practice', 0.85, 'elite_v2', 'system'),
('CEO_V2: Le weekly strategy brief: 1) performances vs objectifs, 2) top 3 actions a prendre, 3) risques detectes, 4) opportunites identifiees. Max 10 lignes.', 'Weekly strategy brief: perfs + 3 actions + risques + opportunites. 10 lignes max', 'ceo', 'best_practice', 0.90, 'elite_v2', 'system'),
('CEO_V2: Le cross-agent learning: si l agent DM decouvre qu un angle de message fonctionne bien, le propager a l agent email et contenu.', 'Cross-agent learning: angle DM fonctionne → propager email + contenu', 'ceo', 'best_practice', 0.88, 'elite_v2', 'system'),
('CEO_V2: Le client context injection: injecter le contexte business du client (secteur, taille, objectifs) dans CHAQUE prompt d agent pour la personnalisation.', 'Client context injection: secteur+taille+objectifs dans chaque prompt agent', 'ceo', 'best_practice', 0.92, 'elite_v2', 'system'),
('CEO_V2: Le performance benchmarking: comparer les metriques du client aux benchmarks du secteur pour identifier les ecarts et les priorites.', 'Performance benchmarking: metriques client vs secteur = ecarts + priorites', 'ceo', 'best_practice', 0.85, 'elite_v2', 'system'),
('CEO_V2: Le quarterly strategy review: tous les 3 mois, reevaluer: la strategie est-elle la bonne? les agents sont-ils optimises? le client est-il satisfait?', 'Quarterly strategy review: strategie + agents + satisfaction client', 'ceo', 'best_practice', 0.85, 'elite_v2', 'system'),
-- MARKETING + TIKTOK + RETENTION MIX (25)
('MARKETING_V2: Le brand awareness funnel: exposition (ads reach) → recognition (brand recall) → consideration (shortlist) → preference → purchase.', 'Brand awareness funnel: exposition → recognition → consideration → preference → purchase', 'marketing', 'best_practice', 0.85, 'elite_v2', 'system'),
('MARKETING_V2: Le marketing mix modeling (MMM) attribue le revenu a chaque canal marketing. Plus precis que le last-click attribution.', 'MMM = attribution revenu par canal. Plus precis que last-click', 'marketing', 'insight', 0.82, 'elite_v2', 'system'),
('MARKETING_V2: Le brand building vs performance marketing: 60% brand (long terme) + 40% performance (court terme) est le split optimal (Binet & Field).', 'Brand 60% + performance 40% = split optimal (Binet & Field)', 'marketing', 'insight', 0.82, 'elite_v2', 'system'),
('MARKETING_V2: Le message-market match: le message doit utiliser les MOTS EXACTS que le client utilise pour decrire son probleme. Pas le jargon interne.', 'Message-market match: mots exacts du client, pas jargon interne', 'marketing', 'best_practice', 0.88, 'elite_v2', 'system'),
('MARKETING_V2: Le viral coefficient calculation: K = (invitations par user) × (taux de conversion). K > 1 = croissance virale. K > 1.5 = explosif.', 'K = invitations × conversion. K>1 viral, K>1.5 explosif', 'marketing', 'insight', 0.85, 'elite_v2', 'system'),
('TIKTOK_V2: Le algorithme TikTok avance: les 500 premieres vues sont le test. Si 20%+ regardent > 75% de la video, TikTok la pousse a 5K→50K→500K.', 'TikTok algo: 500 vues test. 20%+ regardent 75%+ → push 5K→50K→500K', 'tiktok_comments', 'insight', 0.88, 'elite_v2', 'system'),
('TIKTOK_V2: Le trending sound strategy: utiliser un son trending dans les 24h de son emergence maximise la portee. Apres 72h c est trop tard.', 'TikTok son trending: utiliser dans 24h. Apres 72h = trop tard', 'tiktok_comments', 'best_practice', 0.85, 'elite_v2', 'system'),
('TIKTOK_V2: Le hook visuel TikTok: mouvement rapide, couleur vive, texte anime, ou face expressive dans les 0.5 premieres secondes.', 'TikTok hook 0.5s: mouvement + couleur + texte anime + face expressive', 'tiktok_comments', 'best_practice', 0.85, 'elite_v2', 'system'),
('TIKTOK_V2: Le content bucket strategy TikTok: 40% educational, 30% entertaining, 20% inspiring, 10% promotional. Jamais plus de 10% promo.', 'TikTok buckets: 40% edu + 30% fun + 20% inspi + 10% promo', 'tiktok_comments', 'best_practice', 0.82, 'elite_v2', 'system'),
('TIKTOK_V2: Le TikTok SEO: les mots-cles dans la caption, les hashtags, et le texte sur la video sont indexes par le moteur de recherche TikTok.', 'TikTok SEO: mots-cles caption + hashtags + texte video = indexes', 'tiktok_comments', 'insight', 0.85, 'elite_v2', 'system'),
('RETENTION_V2: Le at-risk detection model: combiner usage frequency + feature depth + support tickets + NPS + payment history pour un score predictif.', 'At-risk model: usage + features + tickets + NPS + paiement = score predictif', 'retention', 'best_practice', 0.88, 'elite_v2', 'system'),
('RETENTION_V2: Le save offer hierarchy: 1) education (montrer les features non-decouvertes), 2) upgrade/downgrade offer, 3) pause subscription, 4) discount temporaire.', 'Save hierarchy: education → upgrade/downgrade → pause → discount', 'retention', 'best_practice', 0.85, 'elite_v2', 'system'),
('RETENTION_V2: Le customer lifecycle stage detection: trial → new (J0-30) → growing (J30-90) → established (J90-365) → mature (>365). Adapter le support.', 'Lifecycle: trial → new → growing → established → mature. Adapter support', 'retention', 'best_practice', 0.85, 'elite_v2', 'system'),
('RETENTION_V2: Le product adoption score: nombre de features cles utilisees / nombre total de features cles. Score < 30% = risque de churn.', 'Product adoption score: features utilisees/total. < 30% = risque churn', 'retention', 'insight', 0.85, 'elite_v2', 'system'),
('RETENTION_V2: Le revenue impact analysis: calculer le revenu a risque (MRR des clients at-risk) pour prioriser les actions de retention.', 'Revenue at risk: MRR clients at-risk = prioriser actions retention', 'retention', 'best_practice', 0.85, 'elite_v2', 'system'),
-- ONBOARDING + COMPTABLE + RH AVANCE (20)
('ONBOARDING_V2: Le activation metric identification: les users actives J30 ont fait X et Y dans les 48 premieres heures. X et Y = votre activation metric.', 'Activation metric: actions des users actifs J30 dans 48 premieres heures', 'onboarding', 'best_practice', 0.90, 'elite_v2', 'system'),
('ONBOARDING_V2: Le onboarding friction score: compter le nombre de clics entre signup et aha moment. Chaque clic supprime = +5% activation.', 'Friction score: clics signup→aha. Chaque clic en moins = +5% activation', 'onboarding', 'insight', 0.85, 'elite_v2', 'system'),
('ONBOARDING_V2: Le magic moment engineering: identifier LE moment specifique ou le client realise la valeur. Tout le onboarding doit y mener.', 'Magic moment: moment specifique de realisation valeur. Tout onboarding y mene', 'onboarding', 'best_practice', 0.90, 'elite_v2', 'system'),
('ONBOARDING_V2: Le data-import onboarding: si le client peut importer ses donnees existantes (CSV, API), l activation est 3x plus rapide.', 'Data import onboarding: importer donnees existantes = 3x activation', 'onboarding', 'insight', 0.85, 'elite_v2', 'system'),
('ONBOARDING_V2: Le template-based start: proposer des templates pre-configures par secteur (restaurant, ecommerce, coach) = aha moment instantane.', 'Templates par secteur = aha moment instantane', 'onboarding', 'best_practice', 0.88, 'elite_v2', 'system'),
('COMPTABLE_V2: Le SaaS financial model 13-months: projeter MRR, churn, expansion, CAC, LTV sur 13 mois glissants. MAJ chaque mois.', 'Financial model 13 mois: MRR+churn+expansion+CAC+LTV. MAJ mensuelle', 'comptable', 'best_practice', 0.85, 'elite_v2', 'system'),
('COMPTABLE_V2: Le cost per customer: (infra + API + support + ops) / nombre clients actifs. Doit baisser avec l echelle (economies).', 'Cost per customer: (infra+API+support+ops)/clients. Baisse avec echelle', 'comptable', 'best_practice', 0.82, 'elite_v2', 'system'),
('COMPTABLE_V2: Le revenue waterfall: beginning MRR + new + expansion - churn - contraction = ending MRR. Tracker chaque composant.', 'Revenue waterfall: beginning + new + expansion - churn - contraction = ending MRR', 'comptable', 'best_practice', 0.85, 'elite_v2', 'system'),
('COMPTABLE_V2: Le pricing corridor: le prix doit etre entre le plancher (couts × 3) et le plafond (valeur percue). Le sweet spot est a 60% du plafond.', 'Pricing corridor: plancher (couts×3) → plafond (valeur). Sweet spot 60% plafond', 'comptable', 'insight', 0.82, 'elite_v2', 'system'),
('COMPTABLE_V2: Le tax optimization SaaS FR: CIR/CII (R&D), JEI (exonerations), ACRE (charges), TVA intra-UE (autoliquidation). Tous cumulables.', 'Tax optimization FR: CIR + JEI + ACRE + TVA intra-UE. Cumulables', 'comptable', 'insight', 0.82, 'elite_v2', 'system'),
('RH_V2: Le performance review framework: 70% objectifs mesurables, 20% competences comportementales, 10% contribution a la culture.', 'Performance review: 70% objectifs + 20% comportements + 10% culture', 'rh', 'best_practice', 0.82, 'elite_v2', 'system'),
('RH_V2: Le career pathing: definir 2 parcours (contributeur individuel et manager) avec des niveaux clairs. Evite la promotion par defaut.', 'Career path: IC + manager avec niveaux clairs. Eviter promotion par defaut', 'rh', 'best_practice', 0.80, 'elite_v2', 'system'),
('RH_V2: Le team health check (Spotify model): 8 dimensions evaluees en equipe chaque mois. Detecte les problemes avant qu ils ne s aggravent.', 'Team health check Spotify 8 dimensions/mois = detecter problemes tot', 'rh', 'best_practice', 0.80, 'elite_v2', 'system'),
('RH_V2: Le knowledge sharing rituals: tech talks bi-mensuelles (30 min), retros sprint, documentation post-mortem. Le savoir est collectif.', 'Knowledge sharing: tech talks + retros + post-mortem. Savoir collectif', 'rh', 'best_practice', 0.80, 'elite_v2', 'system'),
('RH_V2: Le succession planning: pour chaque role cle, identifier 2 personnes capables de le remplir en 30 jours. Eviter le single point of failure.', 'Succession planning: 2 remplacants/role cle en 30j. 0 single point failure', 'rh', 'best_practice', 0.82, 'elite_v2', 'system')
ON CONFLICT DO NOTHING;
